import { getMonthLabel } from '@/lib/bs-day-picker/constants'
import {
  formatBsDateWheelLabel,
  formatDayLabel,
  formatYearLabel,
} from '@/lib/bs-day-picker/formatters'
import {
  clampMonth,
  getAllBsDates,
  getCurrentBsDate,
  getMonthData,
  getYears,
} from '@/lib/bs-day-picker/navigation'
import {
  bsDateKey,
  parseBsDateKey,
  type BsDate,
  type BsLocale,
} from '@/lib/bs-day-picker/types'

export function clampBsDate(date: BsDate): BsDate {
  const month = clampMonth({ year: date.year, month: date.month })
  const monthData = getMonthData(month.year, month.month)
  const daysInMonth = monthData?.daysInMonth ?? 30

  return {
    year: month.year,
    month: month.month,
    day: Math.min(Math.max(1, date.day), daysInMonth),
  }
}

export function getDefaultBsDate(): BsDate {
  return getCurrentBsDate()
}

export function getBsDayOptions(year: number, month: number): number[] {
  const monthData = getMonthData(year, month)
  const count = monthData?.daysInMonth ?? 30
  return Array.from({ length: count }, (_, index) => index + 1)
}

export function getBsYearOptions(): number[] {
  return getYears()
}

export function getBsMonthOptions(locale: BsLocale, short = false) {
  return Array.from({ length: 12 }, (_, index) => {
    const month = index + 1
    return {
      value: month,
      label: getMonthLabel(month, locale, short),
    }
  })
}

export function formatBsYearOption(year: number, locale: BsLocale): string {
  return formatYearLabel(year, locale)
}

export function formatBsDayOption(day: number, locale: BsLocale): string {
  return formatDayLabel(day, locale)
}

let cachedBsDateWheelKeys: string[] | null = null

export function getBsDateWheelKeys(): readonly string[] {
  if (!cachedBsDateWheelKeys) {
    cachedBsDateWheelKeys = getAllBsDates().map(bsDateKey)
  }
  return cachedBsDateWheelKeys
}

export function formatBsDateWheelKey(key: string, locale: BsLocale): string {
  const date = parseBsDateKey(key)
  if (!date) return key
  return formatBsDateWheelLabel(date, locale)
}

export function parseBsDateWheelKey(key: string): BsDate | null {
  return parseBsDateKey(key)
}

import { Text } from '@/components/ui/text'
import { cn } from '@/lib/utils'
import * as React from 'react'
import {
  FlatList,
  Platform,
  type ListRenderItemInfo,
  type NativeScrollEvent,
  type NativeSyntheticEvent,
  Pressable,
  View,
} from 'react-native'

const ITEM_HEIGHT = Platform.OS === 'ios' ? 44 : 48
const VISIBLE_COUNT = 5
export const BS_WHEEL_HEIGHT = ITEM_HEIGHT * VISIBLE_COUNT
const EDGE_PADDING = ITEM_HEIGHT * Math.floor(VISIBLE_COUNT / 2)
const DEFAULT_LOOP_REPEATS = 51

type BsWheelColumnProps<T extends string | number> = {
  items: readonly T[]
  selected: T
  onSelect: (value: T) => void
  formatLabel: (value: T) => string
  className?: string
  showOverlay?: boolean
  /** Repeat items and recenter while scrolling for a native infinite wheel feel. */
  loop?: boolean
  loopRepeats?: number
  /** Avoid O(n) lookup when the item list is large (e.g. chronological dates). */
  selectedIndex?: number
}

function normalizeIndex(index: number, length: number): number {
  if (length === 0) return 0
  return ((index % length) + length) % length
}

export function BsWheelColumn<T extends string | number>({
  items,
  selected,
  onSelect,
  formatLabel,
  className,
  showOverlay = true,
  loop = false,
  loopRepeats = DEFAULT_LOOP_REPEATS,
  selectedIndex: selectedIndexProp,
}: BsWheelColumnProps<T>) {
  const listRef = React.useRef<FlatList<T>>(null)
  const isRecenteringRef = React.useRef(false)
  const selectedIndex = Math.max(
    0,
    selectedIndexProp ?? items.indexOf(selected),
  )
  const middleOffset =
    loop && items.length > 0
      ? Math.floor(loopRepeats / 2) * items.length
      : 0

  const data = React.useMemo(() => {
    if (!loop || items.length === 0) return [...items]
    return Array.from(
      { length: items.length * loopRepeats },
      (_, index) => items[normalizeIndex(index, items.length)]!,
    )
  }, [items, loop, loopRepeats])

  const indexForSelected = React.useCallback(
    (index: number) => (loop ? middleOffset + index : index),
    [loop, middleOffset],
  )

  const [focusedIndex, setFocusedIndex] = React.useState(() =>
    indexForSelected(selectedIndex),
  )

  const scrollToIndex = React.useCallback(
    (index: number, animated = false) => {
      if (index < 0 || index >= data.length) return
      listRef.current?.scrollToOffset({
        offset: index * ITEM_HEIGHT,
        animated,
      })
      setFocusedIndex(index)
    },
    [data.length],
  )

  const recenterIfNeeded = React.useCallback(
    (index: number) => {
      if (!loop || items.length === 0) return index

      const edgeBuffer = items.length * 2
      if (index >= edgeBuffer && index < data.length - edgeBuffer) {
        return index
      }

      const normalizedIndex = normalizeIndex(index, items.length)
      const targetIndex = middleOffset + normalizedIndex
      isRecenteringRef.current = true
      listRef.current?.scrollToOffset({
        offset: targetIndex * ITEM_HEIGHT,
        animated: false,
      })
      setFocusedIndex(targetIndex)
      requestAnimationFrame(() => {
        isRecenteringRef.current = false
      })
      return targetIndex
    },
    [data.length, items.length, loop, middleOffset],
  )

  React.useEffect(() => {
    const targetIndex = indexForSelected(selectedIndex)
    // Scroll only — avoid setFocusedIndex here (react-hooks/set-state-in-effect).
    if (targetIndex < 0 || targetIndex >= data.length) return
    listRef.current?.scrollToOffset({
      offset: targetIndex * ITEM_HEIGHT,
      animated: false,
    })
  }, [data.length, indexForSelected, selectedIndex])

  const commitIndex = React.useCallback(
    (index: number) => {
      const boundedIndex = Math.min(
        data.length - 1,
        Math.max(0, Math.round(index)),
      )
      const settledIndex = recenterIfNeeded(boundedIndex)
      const normalizedIndex = loop
        ? normalizeIndex(settledIndex, items.length)
        : settledIndex
      const next = items[normalizedIndex]
      if (next !== undefined && next !== selected) {
        onSelect(next)
      }
    },
    [data.length, items, loop, onSelect, recenterIfNeeded, selected],
  )

  const handleScroll = (event: NativeSyntheticEvent<NativeScrollEvent>) => {
    if (isRecenteringRef.current) return

    const index = Math.min(
      data.length - 1,
      Math.max(0, Math.round(event.nativeEvent.contentOffset.y / ITEM_HEIGHT)),
    )

    if (index !== focusedIndex) {
      setFocusedIndex(index)
    }
  }

  const handleMomentumEnd = (offsetY: number) => {
    commitIndex(offsetY / ITEM_HEIGHT)
  }

  const renderItem = ({ item, index }: ListRenderItemInfo<T>) => {
    const isFocused = index === focusedIndex
    return (
      <Pressable
        className="w-full items-center justify-center px-3"
        style={{ height: ITEM_HEIGHT }}
        onPress={() => {
          scrollToIndex(index, true)
          const normalizedIndex = loop
            ? normalizeIndex(index, items.length)
            : index
          const next = items[normalizedIndex]
          if (next !== undefined) {
            onSelect(next)
          }
        }}
      >
        <Text
          className={cn(
            'w-full text-center text-[17px] leading-[22px]',
            isFocused
              ? 'font-semibold text-foreground'
              : 'font-normal text-muted-foreground/70',
          )}
          numberOfLines={1}
          adjustsFontSizeToFit
          minimumFontScale={0.85}
        >
          {formatLabel(item)}
        </Text>
      </Pressable>
    )
  }

  return (
    <View
      className={cn('relative flex-1', className)}
      style={{ height: BS_WHEEL_HEIGHT }}
    >
      {showOverlay ? (
        <View
          pointerEvents="none"
          className="absolute inset-x-3 top-1/2 z-0 -mt-[22px] h-11 rounded-[10px] bg-[#787880]/20"
        />
      ) : null}
      <FlatList
        ref={listRef}
        data={data}
        style={{ zIndex: 1 }}
        initialScrollIndex={
          data.length > 0 ? Math.min(focusedIndex, data.length - 1) : undefined
        }
        keyExtractor={(item, index) => `${String(item)}-${index}`}
        renderItem={renderItem}
        showsVerticalScrollIndicator={false}
        snapToInterval={ITEM_HEIGHT}
        decelerationRate="fast"
        getItemLayout={(_, index) => ({
          length: ITEM_HEIGHT,
          offset: ITEM_HEIGHT * index,
          index,
        })}
        contentContainerStyle={{ paddingVertical: EDGE_PADDING }}
        onScroll={handleScroll}
        scrollEventThrottle={16}
        onMomentumScrollEnd={(event) =>
          handleMomentumEnd(event.nativeEvent.contentOffset.y)
        }
        onScrollEndDrag={(event) => {
          if (event.nativeEvent.velocity?.y === 0) {
            handleMomentumEnd(event.nativeEvent.contentOffset.y)
          }
        }}
      />
    </View>
  )
}

import { Picker } from '@expo/ui/community/picker'
import {
  clampBsDate,
  formatBsDayOption,
  formatBsYearOption,
  getBsDayOptions,
  getBsMonthOptions,
  getBsYearOptions,
} from '@/lib/bs-picker'
import type { BsDate, BsLocale } from '@/lib/bs-day-picker/types'
import { Platform, View } from 'react-native'

type BsDatePickerWheelsProps = {
  value: BsDate
  locale: BsLocale
  onChange: (value: BsDate) => void
}

const pickerStyle =
  Platform.OS === 'ios' ? { flex: 1, height: 196 } : { flex: 1, minHeight: 48 }

export function BsDatePickerWheels({
  value,
  locale,
  onChange,
}: BsDatePickerWheelsProps) {
  const years = getBsYearOptions()
  const months = getBsMonthOptions(locale, Platform.OS === 'android')
  const days = getBsDayOptions(value.year, value.month)

  const update = (patch: Partial<BsDate>) => {
    onChange(clampBsDate({ ...value, ...patch }))
  }

  return (
    <View className="w-full flex-row gap-1">
      <Picker
        selectedValue={value.year}
        onValueChange={(year) => update({ year: Number(year) })}
        style={pickerStyle}
      >
        {years.map((year) => (
          <Picker.Item
            key={year}
            label={formatBsYearOption(year, locale)}
            value={year}
          />
        ))}
      </Picker>

      <Picker
        selectedValue={value.month}
        onValueChange={(month) => update({ month: Number(month) })}
        style={pickerStyle}
      >
        {months.map((month) => (
          <Picker.Item
            key={month.value}
            label={month.label}
            value={month.value}
          />
        ))}
      </Picker>

      <Picker
        selectedValue={value.day}
        onValueChange={(day) => update({ day: Number(day) })}
        style={pickerStyle}
      >
        {days.map((day) => (
          <Picker.Item
            key={day}
            label={formatBsDayOption(day, locale)}
            value={day}
          />
        ))}
      </Picker>
    </View>
  )
}

import {
  clampBsDate,
  formatBsDateWheelKey,
  getBsDateWheelKeys,
  parseBsDateWheelKey,
} from '@/lib/bs-picker'
import { getBsDateIndex } from '@/lib/bs-day-picker/navigation'
import { bsDateKey } from '@/lib/bs-day-picker/types'
import type { BsDate, BsLocale } from '@/lib/bs-day-picker/types'
import { View } from 'react-native'
import { BsWheelColumn, BS_WHEEL_HEIGHT } from './bs-wheel-column'

type BsDatePickerWheelsProps = {
  value: BsDate
  locale: BsLocale
  onChange: (value: BsDate) => void
}

export function BsDatePickerWheels({
  value,
  locale,
  onChange,
}: BsDatePickerWheelsProps) {
  const dateKeys = getBsDateWheelKeys()
  const clampedValue = clampBsDate(value)
  const selectedKey = bsDateKey(clampedValue)
  const selectedIndex = getBsDateIndex(clampedValue)

  return (
    <View className="w-full px-1" style={{ height: BS_WHEEL_HEIGHT }}>
      <BsWheelColumn
        showOverlay
        className="w-full"
        items={dateKeys}
        selected={selectedKey}
        selectedIndex={selectedIndex >= 0 ? selectedIndex : undefined}
        onSelect={(key) => {
          const next = parseBsDateWheelKey(key)
          if (next) onChange(clampBsDate(next))
        }}
        formatLabel={(key) => formatBsDateWheelKey(key, locale)}
      />
    </View>
  )
}

import {
  clampBsDate,
  formatBsDayOption,
  formatBsYearOption,
  getBsDayOptions,
  getBsMonthOptions,
  getBsYearOptions,
} from '@/lib/bs-picker'
import type { BsDate, BsLocale } from '@/lib/bs-day-picker/types'
import { View } from 'react-native'
import { BsWheelColumn } from './bs-wheel-column'

type BsDatePickerWheelsProps = {
  value: BsDate
  locale: BsLocale
  onChange: (value: BsDate) => void
}

export function BsDatePickerWheels({
  value,
  locale,
  onChange,
}: BsDatePickerWheelsProps) {
  const years = getBsYearOptions()
  const months = getBsMonthOptions(locale, true)
  const days = getBsDayOptions(value.year, value.month)

  const update = (patch: Partial<BsDate>) => {
    onChange(clampBsDate({ ...value, ...patch }))
  }

  return (
    <View className="w-full flex-row px-1">
      <BsWheelColumn
        items={years}
        selected={value.year}
        onSelect={(year) => update({ year })}
        formatLabel={(year) => formatBsYearOption(year, locale)}
      />
      <BsWheelColumn
        loop
        items={months.map((month) => month.value)}
        selected={value.month}
        onSelect={(month) => update({ month })}
        formatLabel={(month) =>
          months.find((entry) => entry.value === month)?.label ??
          String(month)
        }
      />
      <BsWheelColumn
        loop
        items={days}
        selected={value.day}
        onSelect={(day) => update({ day })}
        formatLabel={(day) => formatBsDayOption(day, locale)}
      />
    </View>
  )
}

import { getDefaultBsDate } from '@/lib/bs-picker'
import {
  BS_DATE_DISPLAY_PATTERN,
  formatBsDatePattern,
} from '@/lib/bs-day-picker/pattern'
import type { BsDate, BsLocale } from '@/lib/bs-day-picker/types'
import { cn } from '@/lib/utils'
import { Calendar } from 'lucide-react-native'
import * as React from 'react'
import { BsDatePickerDialog } from './bs-date-picker-dialog.android'
import { Button } from '@/components/ui/button'
import { Icon } from '@/components/ui/icon'
import { Text } from '@/components/ui/text'

export type BsDatePickerProps = {
  value?: BsDate
  onValueChange?: (value: BsDate | undefined) => void
  locale?: BsLocale
  placeholder?: string
  title?: string
  cancelLabel?: string
  confirmLabel?: string
  formatPattern?: string
  formatValue?: (value: BsDate, locale: BsLocale) => string
  className?: string
  disabled?: boolean
}

function resolveDateDisplayLabel(
  value: BsDate,
  locale: BsLocale,
  formatValue?: BsDatePickerProps['formatValue'],
  formatPattern?: string,
): string {
  if (formatValue) return formatValue(value, locale)
  return formatBsDatePattern(
    value,
    formatPattern ?? BS_DATE_DISPLAY_PATTERN,
    locale,
  )
}

export function BsDatePicker({
  value,
  onValueChange,
  locale = 'ne',
  placeholder,
  title,
  cancelLabel,
  confirmLabel,
  formatPattern,
  formatValue,
  className,
  disabled = false,
}: BsDatePickerProps) {
  const resolvedPlaceholder =
    placeholder ?? (locale === 'ne' ? 'मिति छान्नुहोस्' : 'Select date')
  const resolvedTitle = title ?? resolvedPlaceholder
  const resolvedCancel = cancelLabel ?? 'Cancel'
  const resolvedConfirm = confirmLabel ?? 'OK'
  const [showPicker, setShowPicker] = React.useState(false)
  const [tempDate, setTempDate] = React.useState<BsDate>(
    value ?? getDefaultBsDate(),
  )

  const handleOpen = () => {
    if (disabled) return
    setTempDate(value ?? getDefaultBsDate())
    setShowPicker(true)
  }

  const handleCancel = () => {
    setShowPicker(false)
    setTempDate(value ?? getDefaultBsDate())
  }

  const handleConfirm = () => {
    setShowPicker(false)
    onValueChange?.(tempDate)
  }

  const displayLabel = value
    ? resolveDateDisplayLabel(value, locale, formatValue, formatPattern)
    : resolvedPlaceholder

  return (
    <>
      <Button
        variant="outline"
        className={cn('justify-between', className)}
        disabled={disabled}
        onPress={handleOpen}
      >
        <Text className={cn(!value && 'text-muted-foreground')}>
          {displayLabel}
        </Text>
        <Icon as={Calendar} className="size-4 text-muted-foreground" />
      </Button>

      <BsDatePickerDialog
        visible={showPicker}
        value={tempDate}
        locale={locale}
        title={resolvedTitle}
        cancelLabel={resolvedCancel}
        confirmLabel={resolvedConfirm}
        onChange={setTempDate}
        onCancel={handleCancel}
        onConfirm={handleConfirm}
      />
    </>
  )
}
